please mujhe bhi ek phone dedo tech master bhai😭😭
add: Mumbai mankhurd mandala 30 feet road indira nagar -400043
  <style>
    body { margin: 0; background: #222; overflow: hidden; }
    canvas { background: #444; display: block; margin: auto; }
  </style>
</head>
<body>
<canvas id="gameCanvas" width="800" height="600"></canvas>
<script>
const canvas = document.getElementById("gameCanvas");
const ctx = canvas.getContext("2d");

let player = { x: 400, y: 300, size: 20, color: "lime", speed: 5 };
let bullets = [];
let enemies = [
  { x: 100, y: 100, size: 20, color: "red" },
  { x: 700, y: 500, size: 20, color: "red" }
];

document.addEventListener("keydown", (e) => {
  if (e.key === "ArrowUp") player.y -= player.speed;
  if (e.key === "ArrowDown") player.y += player.speed;
  if (e.key === "ArrowLeft") player.x -= player.speed;
  if (e.key === "ArrowRight") player.x += player.speed;
  if (e.key === " ") bullets.push({ x: player.x, y: player.y, dx: 5, dy: 0 });
});

function drawPlayer(p) {
  ctx.fillStyle = p.color;
  ctx.fillRect(p.x, p.y, p.size, p.size);
}

function update() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);

  // Player
  drawPlayer(player);

  // Bullets
  for (let i = 0; i < bullets.length; i++) {
    let b = bullets[i];
    b.x += b.dx;
    b.y += b.dy;
    ctx.fillStyle = "yellow";
    ctx.fillRect(b.x, b.y, 5, 5);

    // Collision with enemies
    for (let j = 0; j < enemies.length; j++) {
      let e = enemies[j];
      if (b.x < e.x + e.size &&
          b.x + 5 > e.x &&
          b.y < e.y + e.size &&
          b.y + 5 > e.y) {
        enemies.splice(j, 1);
        bullets.splice(i, 1);
        i--;
        break;
      }
    }
  }

  // Enemies
  enemies.forEach(drawPlayer);

  requestAnimationFrame(update);
}

update();
</script>
</body>
</html>

